# solution.py
"""Event Organizer Collaborative / Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that lets multiple agents
work together on projects (events): managing users and roles, project
details, task assignment with deadlines and progress tracking, a messaging
platform with attachments, performance dashboards, and exportable reports.

The implementation is dependency-free (standard library only) and keeps all
state in memory behind a single shared re-entrant lock so the same object can
be driven safely from many threads.

Public surface used by the test-suite:

* ``TeamCollaborationManager`` -- the facade exposing every operation.
* Enums: ``TaskStatus``, ``UserRole``, ``ReportFormat``, ``ReportType``.
* Entities: ``Attachment``, ``User``, ``Project``, ``Task``, ``Message``,
  ``Rating``.
* Exceptions: ``TeamCollaborationError`` (base) and the specialised
  ``ValidationError``, ``NotFoundError``, ``AuthorizationError``,
  ``DuplicateError`` and ``ConflictError``.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Sequence, Set, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Exceptions
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when an argument fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles an agent can hold on the platform."""

    ADMIN = "admin"
    MANAGER = "manager"
    MEMBER = "member"
    VIEWER = "viewer"
    GUEST = "guest"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the system can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file shared on a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A platform user / agent."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """An event / project that work is organised around."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work inside a project."""

    id: int
    project_id: int
    title: str
    description: str
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    status: TaskStatus
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    """A chat message / comment, optionally with attachments and replies."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)


@dataclass
class Rating:
    """Peer feedback awarded to a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------
_UNSET = object()


def _copy(obj):
    """Return a defensive deep copy so callers cannot mutate stored state."""

    return copy.deepcopy(obj)


def _is_blank(value) -> bool:
    return value is None or not str(value).strip()


def _validate_email(email) -> None:
    if email is None or not str(email).strip():
        raise ValidationError("email must not be empty")
    if "@" not in str(email):
        raise ValidationError("email must contain '@'")


def _csv_cell(value):
    if value is None:
        return ""
    if isinstance(value, (dict, list, tuple)):
        return str(value)
    if isinstance(value, Enum):
        return value.value
    return value


def _pdf_escape(text: str) -> str:
    return (
        str(text)
        .replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _report_to_lines(report: Dict) -> List[str]:
    """Flatten a report dict into printable text lines for PDF rendering."""

    lines: List[str] = []
    for key, value in report.items():
        if isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_value in value.items():
                lines.append("  {0}: {1}".format(sub_key, sub_value))
        elif isinstance(value, list):
            lines.append("{0}:".format(key))
            for item in value:
                lines.append("  - {0}".format(item))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _build_pdf(title: str, lines: Sequence[str]) -> bytes:
    """Assemble a minimal but structurally valid single-page PDF document."""

    commands = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    commands.append("({0}) Tj".format(_pdf_escape(title)))
    for line in lines:
        commands.append("T*")
        commands.append("({0}) Tj".format(_pdf_escape(line)))
    commands.append("ET")
    content = "\n".join(commands).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        b"<< /Length "
        + str(len(content)).encode("latin-1")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("latin-1")
        pdf += body
        pdf += b"\nendobj\n"

    xref_pos = len(pdf)
    count = len(objects) + 1
    pdf += "xref\n0 {0}\n".format(count).encode("latin-1")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    pdf += (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
            count, xref_pos
        ).encode("latin-1")
    )
    return bytes(pdf)


# ---------------------------------------------------------------------------
# Stores
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common plumbing: every store shares the manager's lock and clock."""

    def __init__(self, manager: "TeamCollaborationManager") -> None:
        self._mgr = manager
        self._lock = manager._lock


class UserStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self._users: Dict[int, User] = {}
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}

    # -- internal (live, no copy) -------------------------------------------
    def _exists(self, user_id: int) -> bool:
        return user_id in self._users

    def _get_live(self, user_id: int) -> User:
        try:
            return self._users[user_id]
        except KeyError:
            raise NotFoundError("user {0} not found".format(user_id))

    def _require(self, user_id: int) -> None:
        if user_id not in self._users:
            raise NotFoundError("user {0} not found".format(user_id))

    # -- public --------------------------------------------------------------
    def register(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if _is_blank(username):
                raise ValidationError("username must not be empty")
            _validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self._username_index:
                raise DuplicateError("username already in use")
            if email in self._email_index:
                raise DuplicateError("email already in use")

            user = User(
                id=self._mgr._new_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._mgr._clock(),
            )
            self._users[user.id] = user
            self._username_index[username] = user.id
            self._email_index[email] = user.id
            return _copy(user)

    def get(self, user_id: int) -> User:
        with self._lock:
            return _copy(self._get_live(user_id))

    def list(self) -> List[User]:
        with self._lock:
            return [_copy(self._users[uid]) for uid in sorted(self._users)]

    def update(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET) -> User:
        with self._lock:
            user = self._get_live(user_id)
            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not _UNSET:
                if _is_blank(username):
                    raise ValidationError("username must not be empty")
                if username != user.username and username in self._username_index:
                    raise DuplicateError("username already in use")
                new_username = username

            if email is not _UNSET:
                _validate_email(email)
                if email != user.email and email in self._email_index:
                    raise DuplicateError("email already in use")
                new_email = email

            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                self._username_index.pop(user.username, None)
                self._username_index[new_username] = user.id
            if new_email != user.email:
                self._email_index.pop(user.email, None)
                self._email_index[new_email] = user.id

            user.username = new_username
            user.email = new_email
            user.role = new_role
            return _copy(user)

    def delete(self, user_id: int) -> None:
        with self._lock:
            user = self._get_live(user_id)
            if self._mgr.projects._user_owns_any(user_id):
                raise ConflictError("user owns one or more projects")
            if self._mgr.tasks._user_has_open_task(user_id):
                raise ConflictError("user has open tasks assigned")

            self._mgr.tasks._drop_assignee(user_id)
            self._username_index.pop(user.username, None)
            self._email_index.pop(user.email, None)
            del self._users[user_id]


class ProjectStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self._projects: Dict[int, Project] = {}

    # -- internal ------------------------------------------------------------
    def _get_live(self, project_id: int) -> Project:
        try:
            return self._projects[project_id]
        except KeyError:
            raise NotFoundError("project {0} not found".format(project_id))

    def _exists(self, project_id: int) -> bool:
        return project_id in self._projects

    def _user_owns_any(self, user_id: int) -> bool:
        return any(p.owner_id == user_id for p in self._projects.values())

    # -- public --------------------------------------------------------------
    def create(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if _is_blank(name):
                raise ValidationError("project name must not be empty")
            self._mgr.users._require(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            project = Project(
                id=self._mgr._new_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._mgr._clock(),
            )
            self._projects[project.id] = project
            return _copy(project)

    def get(self, project_id: int) -> Project:
        with self._lock:
            return _copy(self._get_live(project_id))

    def list(self) -> List[Project]:
        with self._lock:
            return [_copy(self._projects[pid]) for pid in sorted(self._projects)]

    def update(
        self,
        project_id,
        name=_UNSET,
        description=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
    ) -> Project:
        with self._lock:
            project = self._get_live(project_id)

            new_name = project.name
            new_description = project.description
            new_start = project.start_date
            new_end = project.end_date

            if name is not _UNSET:
                if _is_blank(name):
                    raise ValidationError("project name must not be empty")
                new_name = name
            if description is not _UNSET:
                new_description = description or ""
            if start_date is not _UNSET:
                new_start = start_date
            if end_date is not _UNSET:
                new_end = end_date

            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            project.name = new_name
            project.description = new_description
            project.start_date = new_start
            project.end_date = new_end
            return _copy(project)

    def delete(self, project_id: int) -> None:
        with self._lock:
            self._get_live(project_id)
            task_ids = self._mgr.tasks._delete_by_project(project_id)
            self._mgr.messages._delete_by_project(project_id, task_ids)
            del self._projects[project_id]


class TaskStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self._tasks: Dict[int, Task] = {}
        self._project_index: Dict[int, Set[int]] = {}
        self._assignee_index: Dict[int, Set[int]] = {}

    # -- internal ------------------------------------------------------------
    def _get_live(self, task_id: int) -> Task:
        try:
            return self._tasks[task_id]
        except KeyError:
            raise NotFoundError("task {0} not found".format(task_id))

    def _exists(self, task_id: int) -> bool:
        return task_id in self._tasks

    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        return [self._tasks[tid] for tid in self._assignee_index.get(user_id, set())]

    def _tasks_for_project(self, project_id: int) -> List[Task]:
        return [self._tasks[tid] for tid in self._project_index.get(project_id, set())]

    def _all_tasks(self) -> List[Task]:
        return list(self._tasks.values())

    def _user_has_open_task(self, user_id: int) -> bool:
        for tid in self._assignee_index.get(user_id, set()):
            if self._tasks[tid].status != TaskStatus.COMPLETED:
                return True
        return False

    def _set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None:
            bucket = self._assignee_index.get(old)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._assignee_index.pop(old, None)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._assignee_index.setdefault(new_assignee, set()).add(task.id)

    def _drop_assignee(self, user_id: int) -> None:
        for tid in self._assignee_index.pop(user_id, set()):
            task = self._tasks.get(tid)
            if task is not None:
                task.assignee_id = None

    def _delete_by_project(self, project_id: int) -> Set[int]:
        task_ids = set(self._project_index.pop(project_id, set()))
        for tid in task_ids:
            task = self._tasks.pop(tid, None)
            if task is not None and task.assignee_id is not None:
                bucket = self._assignee_index.get(task.assignee_id)
                if bucket is not None:
                    bucket.discard(tid)
                    if not bucket:
                        self._assignee_index.pop(task.assignee_id, None)
        return task_ids

    # -- public --------------------------------------------------------------
    def create(self, project_id, title, assignee_id=None, deadline=None, description="") -> Task:
        with self._lock:
            project = self._mgr.projects._get_live(project_id)
            if _is_blank(title):
                raise ValidationError("task title must not be empty")
            if assignee_id is not None:
                self._mgr.users._require(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._mgr._new_id(),
                project_id=project_id,
                title=title,
                description=description or "",
                assignee_id=None,
                deadline=deadline,
                status=TaskStatus.NOT_STARTED,
                created_at=self._mgr._clock(),
            )
            self._tasks[task.id] = task
            self._project_index.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self._set_assignee(task, assignee_id)
            return _copy(task)

    def get(self, task_id: int) -> Task:
        with self._lock:
            return _copy(self._get_live(task_id))

    def list_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._mgr.projects._get_live(project_id)
            tids = sorted(self._project_index.get(project_id, set()))
            return [_copy(self._tasks[tid]) for tid in tids]

    def list_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._mgr.users._require(user_id)
            tids = sorted(self._assignee_index.get(user_id, set()))
            return [_copy(self._tasks[tid]) for tid in tids]

    def assign(self, task_id: int, user_id: int) -> Task:
        with self._lock:
            task = self._get_live(task_id)
            self._mgr.users._require(user_id)
            self._set_assignee(task, user_id)
            return _copy(task)

    def reassign(self, task_id: int, user_id: int) -> Task:
        return self.assign(task_id, user_id)

    def unassign(self, task_id: int) -> Task:
        with self._lock:
            task = self._get_live(task_id)
            self._set_assignee(task, None)
            return _copy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._get_live(task_id)
            if deadline is not None:
                project = self._mgr.projects._get_live(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return _copy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._get_live(task_id)
            now = self._mgr._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _copy(task)


class MessageStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self._messages: Dict[int, Message] = {}
        self._project_index: Dict[int, Set[int]] = {}
        self._task_index: Dict[int, Set[int]] = {}

    # -- internal ------------------------------------------------------------
    def _get_live(self, message_id: int) -> Message:
        try:
            return self._messages[message_id]
        except KeyError:
            raise NotFoundError("message {0} not found".format(message_id))

    def _build_attachments(
        self, attachments: Optional[Sequence[Tuple[str, bytes]]], uploader_id: int
    ) -> List[Attachment]:
        result: List[Attachment] = []
        for item in attachments or []:
            filename, data = item
            if _is_blank(filename):
                raise ValidationError("attachment filename must not be empty")
            result.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._mgr._clock(),
                )
            )
        return result

    def _delete_by_project(self, project_id: int, task_ids: Set[int]) -> None:
        doomed = set(self._project_index.pop(project_id, set()))
        for tid in task_ids:
            doomed |= self._task_index.pop(tid, set())
        for mid in doomed:
            self._messages.pop(mid, None)

    # -- public --------------------------------------------------------------
    def post(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            self._mgr.users._require(author_id)
            if project_id is not None:
                self._mgr.projects._get_live(project_id)
            if task_id is not None:
                self._mgr.tasks._get_live(task_id)
            if parent_id is not None and parent_id not in self._messages:
                raise NotFoundError("parent message {0} not found".format(parent_id))

            built = self._build_attachments(attachments, author_id)
            if _is_blank(body) and not built:
                raise ValidationError("message body or an attachment is required")

            message = Message(
                id=self._mgr._new_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=self._mgr._clock(),
                edited_at=None,
                attachments=built,
            )
            self._messages[message.id] = message
            if project_id is not None:
                self._project_index.setdefault(project_id, set()).add(message.id)
            if task_id is not None:
                self._task_index.setdefault(task_id, set()).add(message.id)
            return _copy(message)

    def edit(self, message_id: int, editor_id: int, body: str) -> Message:
        with self._lock:
            message = self._get_live(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if _is_blank(body):
                raise ValidationError("message body must not be empty")
            message.body = body
            message.edited_at = self._mgr._clock()
            return _copy(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._get_live(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may attach files")
            if _is_blank(filename):
                raise ValidationError("attachment filename must not be empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=user_id,
                    uploaded_at=self._mgr._clock(),
                )
            )
            return _copy(message)

    def list_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._mgr.projects._get_live(project_id)
            mids = sorted(self._project_index.get(project_id, set()))
            return [_copy(self._messages[mid]) for mid in mids]

    def list_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._mgr.tasks._get_live(task_id)
            mids = sorted(self._task_index.get(task_id, set()))
            return [_copy(self._messages[mid]) for mid in mids]

    def delete(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._get_live(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete this message")
            if message.project_id is not None:
                bucket = self._project_index.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self._task_index.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)
            del self._messages[message_id]


class PerformanceStore(_BaseStore):
    def __init__(self, manager: "TeamCollaborationManager") -> None:
        super().__init__(manager)
        self._ratings: Dict[int, Rating] = {}
        self._ratings_by_ratee: Dict[int, Set[int]] = {}

    # -- internal ------------------------------------------------------------
    @staticmethod
    def _completion_rate(tasks: List[Task]) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_time(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def _summary_for(self, user_id: int) -> Dict:
        rids = self._ratings_by_ratee.get(user_id, set())
        ratings = [self._ratings[rid] for rid in sorted(rids)]
        count = len(ratings)
        average = (sum(r.score for r in ratings) / count) if count else 0.0
        return {
            "count": count,
            "average": average,
            "ratings": [_copy(r) for r in ratings],
        }

    # -- public --------------------------------------------------------------
    def completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._mgr.users._require(user_id)
            return self._completion_rate(self._mgr.tasks._tasks_for_assignee(user_id))

    def average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._mgr.users._require(user_id)
            return self._average_time(self._mgr.tasks._tasks_for_assignee(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._mgr.users._require(rater_id)
            self._mgr.users._require(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if task_id is not None:
                self._mgr.tasks._get_live(task_id)

            rating = Rating(
                id=self._mgr._new_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._mgr._clock(),
            )
            self._ratings[rating.id] = rating
            self._ratings_by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return _copy(rating)

    def ratings_summary(self, user_id: int) -> Dict:
        with self._lock:
            self._mgr.users._require(user_id)
            return self._summary_for(user_id)

    def user_dashboard(self, user_id: int) -> Dict:
        with self._lock:
            self._mgr.users._require(user_id)
            tasks = self._mgr.tasks._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            summary = self._summary_for(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": self._average_time(tasks),
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }


class ReportStore(_BaseStore):
    # -- internal ------------------------------------------------------------
    def _user_stats(self, user: User, tasks: List[Task]) -> Dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        summary = self._mgr.performance._summary_for(user.id)
        return {
            "user_id": user.id,
            "username": user.username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": PerformanceStore._average_time(tasks),
            "rating_count": summary["count"],
            "rating_average": summary["average"],
        }

    # -- public --------------------------------------------------------------
    def project_progress(self, project_id: int) -> Dict:
        with self._lock:
            self._mgr.projects._get_live(project_id)
            tasks = self._mgr.tasks._tasks_for_project(project_id)
            now = self._mgr._clock()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, Dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance(self, project_id: Optional[int] = None) -> Dict:
        with self._lock:
            if project_id is not None:
                self._mgr.projects._get_live(project_id)
                tasks = self._mgr.tasks._tasks_for_project(project_id)
            else:
                tasks = self._mgr.tasks._all_tasks()

            by_user: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                user = self._mgr.users._get_live(user_id)
                rows.append(self._user_stats(user, by_user[user_id]))

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance(self, user_id: int) -> Dict:
        with self._lock:
            user = self._mgr.users._get_live(user_id)
            tasks = sorted(
                self._mgr.tasks._tasks_for_assignee(user_id), key=lambda t: t.id
            )
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            summary = self._mgr.performance._summary_for(user_id)
            task_rows = [
                {
                    "id": t.id,
                    "title": t.title,
                    "project_id": t.project_id,
                    "status": t.status.value,
                    "deadline": t.deadline,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": PerformanceStore._average_time(tasks),
                "rating_count": summary["count"],
                "rating_average": summary["average"],
                "tasks": task_rows,
            }

    def export(self, report, report_format) -> object:
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _to_csv(report: Dict) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        if report.get("report_type") == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([_csv_cell(row.get(col)) for col in header])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, _csv_cell(value)])
        return output.getvalue()

    @staticmethod
    def _to_pdf(report: Dict) -> bytes:
        title = str(report.get("report_type", "report"))
        return _build_pdf(title, _report_to_lines(report))


